const data = $input.first().json;

const cancellationRate = data.TotalTrips > 0 
  ? (data.Cancellations / data.TotalTrips) * 100 
  : 0;

const metrics = {
  totalTrips: data.TotalTrips,
  totalRevenue: data.TotalRevenue?.toFixed(2),
  avgFare: data.AvgFare?.toFixed(2),
  avgDurationMins: data.AvgDurationMins?.toFixed(1),
  avgDistanceKM: data.AvgDistanceKM?.toFixed(1),
  cancellations: data.Cancellations,
  cancellationRate: cancellationRate.toFixed(1),
  ratingsGiven: data.RatingsGiven,
  avgRating: data.AvgRating?.toFixed(2),
  complaints: data.Complaints,
  avgDriverNetEarning: data.AvgDriverNetEarning?.toFixed(2),
  totalGrossEarning: data.TotalGrossEarning?.toFixed(2),
  reportDateKey: data.ReportDateKey,
  flags: {
    lowRating: data.AvgRating < 4.0,
    highCancellation: cancellationRate > 10,
    highComplaints: data.Complaints > 20
  }
};

return [{ json: metrics }];

