const rawOutput = $('AI Agent').item.json.output;

const cleanOutput = rawOutput
  .replace(/\*\*Executive Summary[:\*]*/gi, '')
  .replace(/\*\*/g, '')
  .replace(/\*/g, '')
  .trim();

return [{ json: { cleanSummary: cleanOutput } }];
